content:
            agent_entries.len()
        );

        // Phase 2: Nuke everything (Redb tables + JSON files)
        store.delete_scope(scope_id).await?;
        println!(
            "  Cleared scope '{scope_id}' (Redb tables + knowledge files)"
        );

        // Phase 3: Restore agent entries (write JSON files + insert to Redb)
        if !agent_entries.is_empty() {
            println!(
                "  Restoring {} agent-written entries...",
                agent_entries.len()
            );
            let texts: Vec<String> =
                agent_entries.iter().map(|e| e.content.clone()).collect();
            let embeddings = engine.embed_batch(&texts).await?;
            for (entry, embedding) in agent_entries.iter().zip(embeddings) {
                let mut entry = entry.clone();
                entry.auto_classify();
                entry.embedding = Some(embedding);
                store.insert(&entry).await?;
            }
            println!("  Agent entries restored and re-indexed.");
        }
    }

    let progress = corvia_kernel::ingest::PrintProgress;
    corvia_kernel::ingest::run_workspace_ingest(corvia_kernel::ingest::WorkspaceIngestCtx {
        root,
        config: &config,
        store,
        graph,
        engine,
        repo_filter,
        session_lock: None, // no session lock in CLI mode
        progress: &progress,
    }).await?;

    Ok(())
}
